#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[1005]; scanf("%s", s);
        int cnt[26][2] = {0}; // [letter][parity]
        for (int i = 0; i < N; ++i) {
            int p = i % 2; // 0 -> odd position (1‑based), 1 -> even position
            cnt[s[i]-'a'][p]++;
        }
        int ok = 1;
        for (int c = 0; c < 26; ++c) {
            if (cnt[c][0] != cnt[c][1]) { ok = 0; break; }
        }
        puts(ok ? "YES" : "NO");
    }
    return 0;
}

