  const N = Number(input[idx++]);
  const s = input[idx++];
  const cnt = Array.from({length:26},()=>[0,0]);
  for (let i = 0; i < N; ++i) {
    const p = i % 2; // 0 -> odd position (1‑based)
    const c = s.charCodeAt(i) - 97;
    cnt[c][p]++;
  }
  let ok = true;
  for (let c = 0; c < 26; ++c) {
    if (cnt[c][0] !== cnt[c][1]) { ok = false; break; }
  }
  out.push(ok ? 'YES' : 'NO');
}
